import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminClientDashboard() {
  const [clients, setClients] = useState([]); // सर्व क्लायंट्स साठवण्यासाठी
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // पेज लोड झाल्यावर सर्व डेटा मिळवण्यासाठी useEffect
  useEffect(() => {
    fetchAllClients();
  }, []);

  const fetchAllClients = async () => {
    try {
      // इथे तुझा सर्व क्लायंट्स देणारा API End-point हवा (उदा. /api/all-clients)
      const res = await axios.get('http://localhost:5000/api/all-projects'); 
      setClients(res.data);
      setLoading(false);
    } catch (err) {
      setError("❌ डेटा लोड करण्यात अडचण येत आहे.");
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid py-5 mt-4">
      <div className="row mb-4">
        <div className="col">
          <h2 className="fw-bold text-primary">Freelancer Admin Dashboard</h2>
          <p className="text-muted">येथे तुला सर्व क्लायंट्स आणि त्यांच्या प्रोजेक्टची प्रगती दिसेल.</p>
        </div>
      </div>

      {loading ? (
        <div className="text-center">Loading...</div>
      ) : error ? (
        <div className="alert alert-danger">{error}</div>
      ) : (
        <div className="card shadow-sm border-0 rounded-4">
          <div className="card-body p-0">
            <div className="table-responsive">
              <table className="table table-hover align-middle mb-0">
                <thead className="bg-light">
                  <tr>
                    <th className="ps-4">Client Name</th>
                    <th>Service Type</th>
                    <th>Email</th>
                    <th>Progress</th>
                    <th>Status</th>
                    <th>Payment</th>
                    <th className="text-center">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {clients.map((client, index) => (
                    <tr key={index}>
                      <td className="ps-4">
                        <div className="fw-bold">{client.fullName}</div>
                      </td>
                      <td>{client.serviceType}</td>
                      <td>{client.email}</td>
                      <td style={{ width: '200px' }}>
                        <div className="d-flex align-items-center">
                          <div className="progress w-100 me-2" style={{ height: '8px' }}>
                            <div 
                              className={`progress-bar ${client.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                              style={{ width: `${client.progress}%` }}
                            ></div>
                          </div>
                          <span className="small fw-bold">{client.progress}%</span>
                        </div>
                      </td>
                      <td>
                        <span className={`badge rounded-pill ${client.status === 'Completed' ? 'bg-success' : 'bg-warning text-dark'}`}>
                          {client.status}
                        </span>
                      </td>
                      <td>
                        <span className={`fw-bold ${client.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`}>
                          {client.paymentStatus}
                        </span>
                      </td>
                      <td className="text-center">
                        <button className="btn btn-sm btn-outline-primary me-2">Edit</button>
                        <button className="btn btn-sm btn-outline-danger">Delete</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {clients.length === 0 && !loading && (
        <div className="text-center mt-5">
           <h5>कोणतेही क्लायंट्स सापडले नाहीत.</h5>
        </div>
      )}
    </div>
  );
}

export default AdminClientDashboard;
